 1	import * as React from 'react';
 2	
 3	import { K8sIoApiCoreV1TolerationEffectEnum } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import {
 6	  Button,
 7	  ButtonVariant,
 8	  FormSelect,
 9	  FormSelectOption,
10	  GridItem,
11	  TextInput,
12	} from '@patternfly/react-core';
13	import { MinusCircleIcon } from '@patternfly/react-icons';
14	
15	import { TolerationLabel } from './utils/constants';
16	
17	type TolerationEditRowProps = {
18	  label: TolerationLabel;
19	  onChange: (label: TolerationLabel) => void;
20	  onDelete: (id: any) => void;
21	};
22	
23	const TolerationEditRow: React.FC<TolerationEditRowProps> = ({ label, onChange, onDelete }) => {
24	  const { effect, id, key, value } = label;
25	  const { t } = useKubevirtTranslation();
26	  return (
27	    <>
28	      <GridItem span={4}>
29	        <TextInput
30	          id={`toleration-${id}-key-input`}
31	          isRequired
32	          onChange={(_event, newKey) => onChange({ ...label, key: newKey })}
33	          placeholder={t('Taint key')}
34	          type="text"
35	          value={key}
36	        />
37	      </GridItem>
38	      <GridItem span={4}>
39	        <TextInput
40	          id={`toleration-${id}-value-input`}
41	          isRequired
42	          onChange={(_event, newValue) => onChange({ ...label, value: newValue })}
43	          placeholder={t('Taint value')}
44	          type="text"
45	          value={value}
46	        />
47	      </GridItem>
48	      <GridItem span={3}>
49	        <FormSelect
50	          onChange={(_event, newEffect) =>
51	            onChange({ ...label, effect: newEffect as K8sIoApiCoreV1TolerationEffectEnum })
52	          }
53	          id={`toleration-${id}-effect-select`}
54	          isRequired
55	          value={effect}
56	        >
57	          {Object.values(K8sIoApiCoreV1TolerationEffectEnum).map((effectOption) => (
58	            <FormSelectOption key={effectOption} label={effectOption} value={effectOption} />
59	          ))}
60	        </FormSelect>
61	      </GridItem>
62	      <GridItem span={1}>
63	        <Button
64	          id={`toleration-${id}-delete-btn`}
65	          onClick={() => onDelete(id)}
66	          variant={ButtonVariant.plain}
67	        >
68	          <MinusCircleIcon />
69	        </Button>
70	      </GridItem>
71	    </>
72	  );
73	};
74	
75	export default TolerationEditRow;

